#pragma once

#include <cstdint>
#include <vector>
#include <string>

// --- Forward-declarations ---

// MapTagGroupSystem.cpp includes these definitions.
class System_Map;
struct Map_TagBlock;

// Specialized GroupDescriptor for each tag group.
// (auto-generated by GenerateObject.py).
template <typename TObject>
struct GroupDescriptor;

class TagGroupReader
{
public:
    // Links the Reader to a specific MapSystem using a reference.
    explicit TagGroupReader(System_Map& map) : m_Map(map) {}

    // Specialized entry point for reconstructing a high-level Tag Object 
    // from the map's metadata.
    //
    // Orchestrates the multi-stage reconstruction process for complex tag groups, 
    // transforming raw binary data into a structured C++ object tree:
    //
    // 1. Data Typing: Uses the 'GroupDescriptor' template to resolve the specific 
    //    'TData' raw struct alias. This ensures the binary-to-struct mapping matches 
    //    the tag's layout.
    //
    // 2. Header Loading: Performs a single 'fread' to populate the root 'Data' 
    //    member of the TObject. This captures the fixed-size fields (integers, 
    //    floats, and tag_block headers).
    //
    // 3. Recursive Block Expansion: Invokes 'ReadBlocks()' via the specialized 
    //    descriptor. This phase triggers the auto-generated logic that follows 
    //    every 'tag_block' pointer to read sub-entries, nested blocks, and dynamic 
    //    arrays (the "Logic Layer").
    //
    // After this call, the TObject is fully resident in memory, including all its 
    // dynamically allocated sub-structures.
    template <typename TObject>
    TObject Read(FILE* file, int64_t metaOffset, const std::string& tagName) const
    {
        using TData = typename GroupDescriptor<TObject>::DataType;

        TObject object{};
        object.TagName = tagName;
        if (metaOffset < 0) return object;

        if (fseek(file, (long)metaOffset, SEEK_SET) != 0) return object;
        if (fread(&object.Data, sizeof(TData), 1, file) != 1) return object;

        GroupDescriptor<TObject>::ReadBlocks(file, *this, object);
        return object;
    }

    // Helper method for resolving and loading dynamic arrays (tag_blocks) 
    // from the map file.
    //
    // This function bridges the gap between the static tag header and its dynamic 
    // children by performing the following sequence:
    //
    // 1. Address Resolution: Delegates to 'm_Map.ResolveBlockOffset()' to translate 
    //    the tag's internal memory address (pointer) into a physical file offset.
    //
    // 2. Memory Allocation: Resizes the 'result' vector based on 'block.EntryCount'. 
    //    This ensures a single contiguous memory block is allocated for all entries.
    //
    // 3. Bulk Data Transfer: Executes an 'fseek' to the resolved offset followed 
    //    by a single 'fread'. It reads the entire array into the vector's raw data 
    //    buffer in one operation (O(1) read call per block).
    //
    // Used extensively by auto-generated descriptors to expand nested structures.
    template <typename TEntry>
    std::vector<TEntry> ReadBlock(FILE* file, const Map_TagBlock& block) const
    {
        std::vector<TEntry> result;
        int64_t offset = m_Map.ResolveBlockOffset(block);
        if (offset < 0) return result;

        result.resize(block.EntryCount);
        if (fseek(file, (long)offset, SEEK_SET) != 0) return result;
        fread(result.data(), sizeof(TEntry), (size_t)block.EntryCount, file);
        return result;
    }

private:
    System_Map& m_Map;
};